import hashlib

# Node type constants
EMPTY = 0
BRANCH = 1
LEAF = 2
EXTENSION = 3

def sha3(data):
 """Keccak-256 hash (Ethereum's sha3)"""
 return hashlib.sha3_256(data).hexdigest()

def encode_node(node_type, encoded_data):
 """RLP encode node with type prefix"""
 # RLP (Recursive Length Prefix) encoding
 if node_type == LEAF:
 return sha3(bytes([LEAF]) + encoded_data)
 elif node_type == EXTENSION:
 return sha3(bytes([EXTENSION]) + encoded_data)
 elif node_type == BRANCH:
 return sha3(bytes([BRANCH]) + encoded_data)
 return b''

class MPTNode:
 def __init__(self, node_type, data=None):
 self.node_type = node_type # EMPTY, BRANCH, LEAF, EXTENSION
 self.data = data or {}
 self.hash = None

 def compute_hash(self):
 """Recursively compute hash of this node and children"""
 if self.node_type == EMPTY:
 self.hash = sha3(b'')
 return self.hash

 # Serialize node data (RLP encoding simplified)
 encoded = self._serialize()
 self.hash = sha3(encoded)
 return self.hash

 def _serialize(self):
 """Convert node to bytes for hashing"""
 if self.node_type == LEAF:
 key = self.data.get('key', b'')
 value = self.data.get('value', b'')
 return bytes([LEAF]) + key + value
 elif self.node_type == EXTENSION:
 prefix = self.data.get('prefix', b'')
 child_hash = self.data.get('child_hash', b'')
 return bytes([EXTENSION]) + prefix + child_hash
 elif self.node_type == BRANCH:
 # 16 children + optional value
 result = b''
 for i in range(16):
 result += self.data.get(f'child_{i}', b'')
 if 'value' in self.data:
 result += self.data['value']
 return bytes([BRANCH]) + result
 return b''

